export function svgFor(name: string, color: string, strokeWidth = 2): string | null {
  const glyph = ICONS[name];
  if (!glyph) return null;
  const vb = glyph.viewBox ?? '0 0 24 24';
  if (glyph.type === 'stroke') {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="${vb}" fill="none" stroke="${color}" stroke-width="${strokeWidth}" stroke-linecap="round" stroke-linejoin="round">${glyph.body}</svg>`;
  }
  if (glyph.type === 'fill') {
    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="${vb}" fill="${color}">${glyph.body}</svg>`;
  }
  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="${vb}">${glyph.body}</svg>`;
}
